import java.util.*;

public class Solution {

    // Helper class for Dijkstra's priority queue
    static class Node implements Comparable<Node> {
        long distance;
        int id;

        public Node(long distance, int id) {
            this.distance = distance;
            this.id = id;
        }

        @Override
        public int compareTo(Node other) {
            return Long.compare(this.distance, other.distance);
        }
    }

    // Graph representation: Adjacency list where each entry stores (neighbor, weight)
    static class Edge {
        int to;
        long weight;

        public Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    /**
     * Runs Dijkstra's algorithm from a single source node.
     * 
     * @param N Number of nodes.
     * @param adj Adjacency list representation of the graph.
     * @param start The starting node index.
     * @return An array containing the shortest distance from 'start' to all other nodes.
     */
    private static long[] dijkstra(int N, List<List<Edge>> adj, int start) {
        long[] dist = new long[N];
        Arrays.fill(dist, Long.MAX_VALUE);

        PriorityQueue<Node> pq = new PriorityQueue<>();

        dist[start] = 0;
        pq.add(new Node(0, start));

        while (!pq.isEmpty()) {
            Node current = pq.poll();
            long d = current.distance;
            int u = current.id;

            if (d > dist[u]) {
                continue;
            }

            for (Edge edge : adj.get(u)) {
                int v = edge.to;
                long weight = edge.weight;

                if (dist[u] != Long.MAX_VALUE && dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.add(new Node(dist[v], v));
                }
            }
        }
        return dist;
    }

    public static long[] solve(long nLong, long[] prices, long[][] roads) {
        int N = (int) nLong;

        // --- Step 1: Build Graphs ---

        // Graph 1: Empty Hand (Weight = cost)
        List<List<Edge>> adjEmpty = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            adjEmpty.add(new ArrayList<>());
        }

        // Graph 2: Carrying Apple (Weight = cost * tax)
        List<List<Edge>> adjCarry = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            adjCarry.add(new ArrayList<>());
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];

            // Empty Hand Graph (Bidirectional)
            adjEmpty.get(u).add(new Edge(v, cost));
            adjEmpty.get(v).add(new Edge(u, cost));

            // Carrying Apple Graph (Bidirectional)
            long carryWeight = cost * tax;
            adjCarry.get(u).add(new Edge(v, carryWeight));
            adjCarry.get(v).add(new Edge(u, carryWeight));
        }

        // --- Step 2: Calculate All-Pairs Shortest Paths (APSP) ---

        // D_empty[i][j]: Shortest path i -> j with empty hands
        long[][] D_empty = new long[N][N];
        for (int i = 0; i < N; i++) {
            long[] distFromI = dijkstra(N, adjEmpty, i);
            for (int j = 0; j < N; j++) {
                D_empty[i][j] = distFromI[j];
            }
        }

        // D_carry[j][i]: Shortest path j -> i while carrying an apple (we need this for return trip)
        // Since we run Dijkstra N times, we calculate shortest paths from j to all i.
        long[][] D_carry = new long[N][N];
        for (int j = 0; j < N; j++) {
            // Run Dijkstra starting at j in the carrying graph
            long[] distFromJ = dijkstra(N, adjCarry, j);
            for (int i = 0; i < N; i++) {
                // distFromJ[i] is the cost from j to i while carrying
                D_carry[j][i] = distFromJ[i];
            }
        }

        // --- Step 3: Calculate Minimum Cost for each store i ---
        long[] ans = new long[N];

        for (int i = 0; i < N; i++) {
            // Option 1: Buy directly at i
            long minCost = prices[i];

            // Option 2: Go to store j, buy, and return to i
            for (int j = 0; j < N; j++) {
                if (i == j) continue;

                // Cost to go i -> j (empty)
                long cost_i_to_j_empty = D_empty[i][j];

                // Cost to return j -> i (carrying)
                long cost_j_to_i_carry = D_carry[j][i];

                // Check if paths exist (not infinity)
                if (cost_i_to_j_empty != Long.MAX_VALUE && cost_j_to_i_carry != Long.MAX_VALUE) {
                    // Total Cost = Travel (i->j) + Purchase (at j) + Travel (j->i)
                    long totalCost = cost_i_to_j_empty + prices[j] + cost_j_to_i_carry;
                    minCost = Math.min(minCost, totalCost);
                }
            }
            ans[i] = minCost;
        }

        return ans;
    }
